const raw = $json;
let normalized = raw;

if (raw.output && typeof raw.output === 'object' && !Array.isArray(raw.output)) {
  normalized = raw.output;
} else if (raw.response && typeof raw.response === 'object' && !Array.isArray(raw.response)) {
  normalized = raw.response;
} else if (raw.text && typeof raw.text === 'string') {
  try {
    normalized = JSON.parse(raw.text);
  } catch (e) {
    throw new Error(`Model returned unparseable compile output: ${raw.text.slice(0, 1000)}`);
  }
}

return [{
  json: {
    ...normalized,
    graph_id: $('Build Compile Request').first().json.graphId,
    graph_name: $('Build Compile Request').first().json.graphName,
    source_prompt: $('Build Compile Request').first().json.sourcePrompt,
    compiled_at: $('Build Compile Request').first().json.compiledAt
  }
}];

const manifest = { ...$json };
const prompts = manifest.prompts || [];

if (!Array.isArray(prompts) || prompts.length === 0) {
  throw new Error('Manifest contains no prompts');
}

const idSet = new Set();
const promptById = {};

for (const p of prompts) {
  if (!p.id) throw new Error('A prompt is missing id');
  if (idSet.has(p.id)) throw new Error(`Duplicate prompt id: ${p.id}`);
  idSet.add(p.id);
  promptById[p.id] = p;
}

for (const p of prompts) {
  for (const dep of (p.depends_on || [])) {
    if (!idSet.has(dep)) {
      throw new Error(`Prompt ${p.id} references unknown dependency ${dep}`);
    }
  }
}

const recombineSteps = prompts.filter(p => p.execution_mode === 'recombine');
if (recombineSteps.length !== 1) {
  throw new Error(`Manifest must contain exactly one recombination prompt. Found ${recombineSteps.length}`);
}
if (recombineSteps[0].id !== 'P_FINAL') {
  throw new Error(`Recombination prompt must use id P_FINAL`);
}

const indegree = {};
const edges = {};

for (const p of prompts) {
  indegree[p.id] = (p.depends_on || []).length;
  edges[p.id] = [];
}

for (const p of prompts) {
  for (const dep of (p.depends_on || [])) {
    edges[dep].push(p.id);
  }
}

let queue = prompts
  .filter(p => indegree[p.id] === 0)
  .map(p => p.id)
  .sort();

const execution_order = [];

while (queue.length) {
  const id = queue.shift();
  execution_order.push(promptById[id]);

  for (const next of edges[id]) {
    indegree[next] -= 1;
    if (indegree[next] === 0) {
      queue.push(next);
      queue.sort();
    }
  }
}

if (execution_order.length !== prompts.length) {
  throw new Error('Cycle detected in prompt graph');
}

return [{
  json: {
    ...manifest,
    prompt_count: prompts.length,
    execution_order
  }
}];
